}






void InitPerRun() 
{
	int i;
	for (i=0; i<Size*Size; i++)
			*(m+i) = 0.0;
}









void ForwardSub(cl_context context, cl_device_id device)
{
	int t;
    cl_mem m_cl, a_cl, b_cl;
    cl_int err;

    cl_command_queue queue = cl_getCommandQueue();

    cl_program program = cl_compileProgram("translated_0.cl", "", false);
    cl_kernel kernel1 = cl_createKernel(program, "Fan1");
    cl_kernel kernel2 = cl_createKernel(program, "Fan2");

    m_cl = cl_allocBuffer(Size * Size * sizeof(float), CL_MEM_READ_WRITE);
    a_cl = cl_allocBuffer(Size * Size * sizeof(float), CL_MEM_READ_WRITE);
    b_cl = cl_allocBuffer(Size * sizeof(float), CL_MEM_READ_WRITE);

    cl_copyBufferToDevice(m_cl, m, Size * Size * sizeof(float), CL_TRUE);
    cl_copyBufferToDevice(a_cl, a, Size * Size * sizeof(float), CL_TRUE);
    cl_copyBufferToDevice(b_cl, b, Size * sizeof(float), CL_TRUE);

    int block_size, grid_size;

    block_size = MAXBLOCKSIZE;
    grid_size = (Size/block_size) + (!(Size%block_size)? 0:1);

    size_t dimBlock1[] = {block_size, 1, 1};
    size_t dimGrid1[] = {grid_size, 1, 1};

    int blockSize2d, gridSize2d;
    blockSize2d = BLOCK_SIZE_XY;
    gridSize2d = (Size/blockSize2d) + (!(Size%blockSize2d?0:1)); 

    size_t dimBlock2[] = {blockSize2d, blockSize2d, 1};
    size_t dimGrid2[] = {gridSize2d, gridSize2d, 1};

#ifdef  TIMING
    gettimeofday(&tv_kernel_start, NULL);
#endif


    struct timeval time_start;
    gettimeofday(&time_start, NULL);
    for (t=0; t<(Size-1); t++) {
        cl_setKernelArg(kernel1, 0, sizeof(cl_mem), &m_cl);
        cl_setKernelArg(kernel1, 1, sizeof(cl_mem), &a_cl);
        cl_setKernelArg(kernel1, 2, sizeof(int), &Size);
        cl_setKernelArg(kernel1, 3, sizeof(int), &t);

        err = clEnqueueTask(queue, kernel1, dimBlock1, dimGrid1, NULL, NULL);
        checkCLError(err, "Fan1 enqueue");
        cl_sync();

        cl_setKernelArg(kernel2, 0, sizeof(cl_mem), &m_cl);
        cl_setKernelArg(kernel2, 1, sizeof(cl_mem), &a_cl);
        cl_setKernelArg(kernel2, 2, sizeof(cl_mem), &b_cl);
        cl_setKernelArg(kernel2, 3, sizeof(int), &Size);
        cl_setKernelArg(kernel2, 4, sizeof(int), &Size-t); // j1 mapped to arg 4
        cl_setKernelArg(kernel2, 5, sizeof(int), &t);

        err = clEnqueueTask(queue, kernel2, dimBlock2, dimGrid2, NULL, NULL);
        checkCLError(err, "Fan2 enqueue");
        cl_sync();
    }

    struct timeval time_end;
    gettimeofday(&time_end, NULL);
    totalKernelTime = (time_end.tv_sec * 1000000 + time_end.tv_usec) - (time_start.tv_sec * 1000000 + time_start.tv_usec);

#ifdef  TIMING
    tvsub(&time_end, &tv_kernel_start, &tv);
    kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

    cl_copyBufferToHost(m, m_cl, Size * Size * sizeof(float), CL_TRUE);
    cl_copyBufferToHost(a, a_cl, Size * Size * sizeof(float), CL_TRUE);
    cl_copyBufferToHost(b, b_cl, Size * sizeof(float), CL_TRUE);

    cl_freeMem(m_cl);
    cl_freeMem(a_cl);
    cl_freeMem(b_cl);
    cl_freeKernel(kernel1);
    cl_freeKernel(kernel2);
    cl_freeProgram(program);
}






void BackSub()
{

	finalVec = (float *) malloc(Size * sizeof(float));

	int i,j;
	for(i=0;i<Size;i++){
		finalVec[Size-i-1]=b[Size-i-1];
		for(j=0;j<i;j++)
		{
			finalVec[Size-i-1]-=*(a+Size*(Size-i-1)+(Size-j-1)) * finalVec[Size-j-1];
		}
		finalVec[Size-i-1]=finalVec[Size-i-1]/ *(a+Size*(Size-i-1)+(Size-i-1));
	}
}

